const should = require('should');
const expect = require('chai').expect;
const assert = require('chai').assert;
const PromiseFactory = require('logged-promise');
const async = require('async');

const ModelFactory = require('../../index');

const config = require('../config');
const ConfigHelper = require('../helpers/ConfigHelper');

const serviceInit = {
	requestId: "TEST-" + require('uuid/v1')(),
	currentUser: {
		organizationId: 1,
		userId: 1,
		username: 'test@corebit.tech'
	}
};

PromiseFactory.appStart(ConfigHelper.getLogger());

describe("Model Configuration Tests", function () {
	this.timeout(150000);


	it("It starts ModelFactory with empty logger", (done) => {
		expect(() => {
			ModelFactory.appStart();
		}).to.throw(Error, /logger is null or undefined/);


		done();
	});

	it("It starts ModelFactory without logger.debug", (done) => {
		expect(() => {
			ModelFactory.appStart({});
		}).to.throw(Error, /logger.debug is not a function/);

		done();
	});


	it("It starts ModelFactory with empty config", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger());
		}).to.throw(Error, /config is null or undefined/);

		done();
	});

	it("It starts ModelFactory with empty config", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {});
		}).to.throw(Error, /config.database is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.database", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {}
			});
		}).to.throw(Error, /config.database.database is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.user", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: ""
				}
			});
		}).to.throw(Error, /config.database.user is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.password", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: "",
					user: ""
				}
			});
		}).to.throw(Error, /config.database.password is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.host", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: "",
					user: "",
					password: ""
				}
			});
		}).to.throw(Error, /config.database.host is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.port", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: "",
					user: "",
					password: "",
					host: ""
				}
			});
		}).to.throw(Error, /config.database.port is null or undefined/);

		done();
	});

	it("It starts ModelFactory without config.database.dialect", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: "",
					user: "",
					password: "",
					host: "",
					port: ""
				}
			});
		}).to.throw(Error, /config.database.dialect is null or undefined/);

		done();
	});


	it("It initializes ModelFactory with invalid serviceInit", (done) => {
		expect(() => {
			ModelFactory.appStart(ConfigHelper.getLogger(), {
				database: {
					database: "",
					user: "",
					password: "",
					host: "",
					port: "",
					dialect: ""
				}
			});
		}).to.throw(Error, /The dialect  is not supported. Supported dialects: mariadb, mssql, mysql, postgres, and sqlite/);

		done();
	});

	it("It initializes ModelFactory with invalid serviceInit", (done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, () => {
			expect(ModelFactory.init).to.throw(Error, /Invalid serviceInit/);
			done();
		});


	});


	it("It initializes ModelFactory without requestId", (done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, () => {
			expect(() => {
				ModelFactory.init({});
			}).to.throw(Error, /Invalid serviceInit/);
			done();
		});
	});
});